"use client";

import { useState } from "react";
import { useSession } from "next-auth/react";
import { useRecentCheckpoints } from "@/hooks/use-recent-commits";
import { StatCard } from "@/components/ui/stat-card";
import { Heatmap } from "@/components/ui/heatmap";
import { EmptyState } from "@/components/ui/empty-state";
import { Skeleton } from "@/components/ui/skeleton";
import { RecentCommitsTable } from "@/components/repo/recent-commits-table";

function getGreeting(): string {
  const hour = new Date().getHours();
  if (hour < 12) return "Morning";
  if (hour < 18) return "Afternoon";
  return "Evening";
}

export default function OverviewPage() {
  const { data: session } = useSession();
  const { items, heatmap, isLoading } = useRecentCheckpoints();

  const firstName = session?.user?.name?.split(" ")[0] || "there";

  // Checkpoints created in the last 24 hours
  const [now] = useState(() => Date.now());
  const checkpoints24h =
    items?.filter(
      (item) =>
        now - new Date(item.checkpoint.created_at).getTime() < 86_400_000
    ).length ?? 0;

  const heatmapData = heatmap ?? {};
  const hasCheckpoints = (items?.length ?? 0) > 0;

  if (isLoading) {
    return (
      <div className="space-y-6">
        <Skeleton className="h-8 w-64" />
        <div className="flex gap-4">
          <Skeleton className="h-24 w-44 shrink-0" />
          <Skeleton className="h-24 flex-1" />
        </div>
        <Skeleton className="h-48" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <h2 className="text-lg font-semibold text-foreground">
        {getGreeting()}, {firstName}
      </h2>

      <div className="flex gap-4">
        <StatCard
          label="Checkpoints (24h)"
          value={checkpoints24h}
          className="w-44 shrink-0"
        />
        <Heatmap data={heatmapData} className="min-w-0 flex-1" />
      </div>

      {hasCheckpoints && (
        <div className="space-y-3">
          <h3 className="text-sm font-medium text-muted">Recent Activity</h3>
          <RecentCommitsTable />
        </div>
      )}

      {!hasCheckpoints && (
        <EmptyState
          title="No checkpoints yet"
          description="Run partio commit in a repo to capture your first checkpoint."
        />
      )}
    </div>
  );
}

